import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate a monthly payment?", a: "A monthly loan payment is calculated from the loan amount, monthly interest rate, and total number of payments. This payment calculator uses the standard amortized loan formula so each payment includes principal and interest." },
  { q: "What is the formula for monthly loan payments?", a: "The formula is M = P[r(1+r)^n] / [(1+r)^n - 1], where M is monthly payment, P is principal, r is the monthly interest rate, and n is the number of monthly payments." },
  { q: "How does loan term affect monthly payment?", a: "A longer loan term usually lowers the monthly payment but increases total interest. A shorter term has higher monthly payments but normally costs less overall." },
  { q: "What happens if you pay extra on your loan?", a: "Extra payments reduce the remaining principal faster. That can lower total interest and may help you pay the loan off sooner." },
  { q: "How do you calculate how much you can afford to borrow?", a: "Enter the monthly payment you can afford, the interest rate, and the term. The calculator converts that payment into an estimated loan amount using the present value of an amortized loan." },
];

const money = (value: number, digits = 2) => formatCurrencyValue(value, { maximumFractionDigits: digits });

function monthlyPayment(principal: number, annualRate: number, months: number) {
  if (principal <= 0 || months <= 0) return 0;
  const monthlyRate = annualRate / 100 / 12;
  if (monthlyRate === 0) return principal / months;
  const factor = Math.pow(1 + monthlyRate, months);
  return principal * monthlyRate * factor / (factor - 1);
}

function affordablePrincipal(payment: number, annualRate: number, months: number) {
  if (payment <= 0 || months <= 0) return 0;
  const monthlyRate = annualRate / 100 / 12;
  if (monthlyRate === 0) return payment * months;
  const factor = Math.pow(1 + monthlyRate, months);
  return payment * (factor - 1) / (monthlyRate * factor);
}

export default function PaymentCalculator() {
  useCurrencyVersion();
  const [mode, setMode] = useState<"payment" | "borrow">("payment");
  const [loanAmount, setLoanAmount] = useState(10000);
  const [desiredPayment, setDesiredPayment] = useState(300);
  const [annualRate, setAnnualRate] = useState(6);
  const [termMonths, setTermMonths] = useState(36);

  const principal = mode === "payment" ? loanAmount : affordablePrincipal(desiredPayment, annualRate, termMonths);
  const payment = mode === "payment" ? monthlyPayment(loanAmount, annualRate, termMonths) : desiredPayment;
  const totalPayment = payment * termMonths;
  const totalInterest = Math.max(0, totalPayment - principal);

  const comparisonRows = [1000, 5000, 10000, 25000, 50000].map((amount) => ({
    amount,
    m12: monthlyPayment(amount, 6, 12),
    m24: monthlyPayment(amount, 6, 24),
    m36: monthlyPayment(amount, 6, 36),
    m60: monthlyPayment(amount, 6, 60),
  }));

  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  return (
    <>
      <SEOHead
        title="Free Payment Calculator Online - Calculate Monthly Payments for Any Loan Instantly | CalcHive"
        description="Free online payment calculator. Calculate monthly payment for any loan or find how much you can borrow from a desired monthly payment instantly. 100% free, no signup required."
        canonical="/payment-calculator"
        keywords="free payment calculator, monthly payment calculator free online, loan payment calculator free, calculate monthly payment free, how much can I borrow calculator free"
        category="Financial Calculators"
        breadcrumbName="Free Payment Calculator Online"
        schemaType="WebApplication"
        schemaApplicationCategory="CalculatorApplication"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Payment Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free payment calculator to calculate monthly payment free or find how much you can borrow from a desired monthly payment.</p>
        </div>

        <AdPlaceholder size="banner" className="mb-8" />

        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">Calculation mode</label>
              <select value={mode} onChange={(event) => setMode(event.target.value as "payment" | "borrow")} className={inputClass}>
                <option value="payment">Calculate monthly payment</option>
                <option value="borrow">Find how much I can borrow</option>
              </select>
            </div>
            {mode === "payment" ? (
              <div>
                <label className="text-sm font-semibold text-foreground block mb-2">Loan amount</label>
                <input type="number" min="0" value={loanAmount} onChange={(event) => setLoanAmount(Number(event.target.value))} className={inputClass} />
              </div>
            ) : (
              <div>
                <label className="text-sm font-semibold text-foreground block mb-2">Desired monthly payment</label>
                <input type="number" min="0" value={desiredPayment} onChange={(event) => setDesiredPayment(Number(event.target.value))} className={inputClass} />
              </div>
            )}
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">Annual interest rate (%)</label>
              <input type="number" min="0" step="0.1" value={annualRate} onChange={(event) => setAnnualRate(Number(event.target.value))} className={inputClass} />
            </div>
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">Loan term (months)</label>
              <input type="number" min="1" value={termMonths} onChange={(event) => setTermMonths(Number(event.target.value))} className={inputClass} />
            </div>
          </div>

          <motion.div key={`${mode}-${loanAmount}-${desiredPayment}-${annualRate}-${termMonths}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{mode === "payment" ? "Monthly Payment" : "Estimated Borrowing Amount"}</p>
              <p className="text-5xl sm:text-6xl font-black text-white tracking-tight" data-testid="result-payment">{mode === "payment" ? money(payment) : money(principal)}</p>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">
              {[
                ["Principal", principal],
                ["Total Interest", totalInterest],
                ["Total Payments", totalPayment],
              ].map(([label, value]) => (
                <div key={label as string} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label as string}</p>
                  <p className="text-lg font-extrabold text-foreground">{money(value as number)}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>

        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Monthly Payments for Any Loan for Free</h2>
          <p className="text-muted-foreground leading-relaxed">This monthly payment calculator free online uses loan amount, annual interest rate, and repayment term to estimate the fixed payment for an amortized loan.</p>

          <h2 className="text-2xl font-bold text-foreground">How to Find How Much You Can Borrow From a Monthly Payment</h2>
          <p className="text-muted-foreground leading-relaxed">Switch to reverse mode, enter the payment you can afford, and the calculator estimates the loan principal supported by that payment.</p>

          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <caption className="caption-top text-left font-bold text-foreground mb-3">Monthly Payments by Loan Amount and Term</caption>
              <thead className="bg-muted/60">
                <tr>{["Loan Amount", "12 Months", "24 Months", "36 Months", "60 Months (at 6% rate)"].map((heading) => <th key={heading} className="text-left py-3 px-3 font-semibold text-foreground">{heading}</th>)}</tr>
              </thead>
              <tbody className="divide-y divide-border">
                {comparisonRows.map((row) => (
                  <tr key={row.amount} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{money(row.amount, 0)}</td>
                    <td className="py-2.5 px-3">{money(row.m12)}</td>
                    <td className="py-2.5 px-3">{money(row.m24)}</td>
                    <td className="py-2.5 px-3">{money(row.m36)}</td>
                    <td className="py-2.5 px-3">{money(row.m60)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Loan Payment Tool for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>{["Item", "Amount"].map((heading) => <th key={heading} className="text-left py-3 px-3 font-semibold text-foreground">{heading}</th>)}</tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Principal or borrowing amount", money(principal)],
                  ["Monthly payment", money(payment)],
                  ["Total interest", money(totalInterest)],
                  ["Total cost", money(totalPayment)],
                ].map(([label, value]) => (
                  <tr key={label}>
                    <td className="py-2.5 px-3 font-semibold text-foreground">{label}</td>
                    <td className="py-2.5 px-3 text-sky-600 dark:text-sky-400 font-semibold">{value}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div>
        </section>

        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/payment-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


